starterCode:
// Bug 1: URL salah — API tidak mengembalikan data seperti yang diharapkan
// Bug 2: Response tidak dicek status-nya sebelum parsing JSON
// Bug 3: .catch() dipasang sebelum .then() — urutan rantai salah

fetch('https://jsonplaceholder.typicode.com/users/999')
  .catch(function(error) {
    console.log('Error: ' + error.message);
  })
  .then(function(response) {
    return response.json();
  })
  .then(function(data) {
    if (!data.name) {
      throw new Error('Pengguna tidak ditemukan');
    }
    console.log(data.name);
  });

solution:
fetch('https://jsonplaceholder.typicode.com/users/999')
  .then(function(response) {
    if (!response.ok) {
      throw new Error('Gagal mengambil data: ' + response.status);
    }
    return response.json();
  })
  .then(function(data) {
    if (!data.name) {
      throw new Error('Pengguna tidak ditemukan');
    }
    console.log(data.name);
  })
  .catch(function(error) {
    console.log('Error: ' + error.message);
  });

verification.testCode:
const code = solution;
assert(code.includes('.catch('), 'Harus memiliki .catch() untuk penanganan error');
assert(code.indexOf('.then(') < code.indexOf('.catch('), '.catch() harus berada di akhir rantai, setelah semua .then()');
assert(code.includes('response.ok'), 'Harus mengecek response.ok sebelum parsing JSON');
